post() {
  local table=$1
  local data=$2
  local code=$(curl -s -o /dev/null -w "%{http_code}" "${URL}/${table}" -X POST \
    -H "apikey: ${SRK}" \
    -H "Authorization: Bearer ${SRK}" \
    -H "Content-Type: application/json" \
    -H "Prefer: return=minimal,resolution=ignore-duplicates" \
    --data-raw "${data}")
  echo "  ${table}: HTTP ${code}"
}

patch() {
  local table=$1
  local filter=$2
  local data=$3
  local code=$(curl -s -o /dev/null -w "%{http_code}" "${URL}/${table}?${filter}" -X PATCH \
    -H "apikey: ${SRK}" \
    -H "Authorization: Bearer ${SRK}" \
    -H "Content-Type: application/json" \
    -H "Prefer: return=minimal" \
    --data-raw "${data}")
  echo "  ${table} (PATCH): HTTP ${code}"
}

